import React, { useState } from 'react';

export default function ApologyWebsite() {
  const [forgiven, setForgiven] = useState(false);
  const [noClicks, setNoClicks] = useState(0);

  const handleNoClick = () => {
    setNoClicks(noClicks + 1);
  };

  return (
    <div className="min-h-screen bg-[#c87e7e] flex flex-col items-center justify-center py-12 px-4 font-sans text-white overflow-x-hidden relative">
      
      {/* Floating Hearts Animation */}
      <style dangerouslySetInnerHTML={{__html: `
        @import url('https://fonts.googleapis.com/css2?family=Pacifico&display=swap');
        .font-pacifico { font-family: 'Pacifico', cursive; }
        
        @keyframes float {
          0% {
            transform: translateY(100vh) translateX(0) rotate(0deg);
            opacity: 1;
          }
          100% {
            transform: translateY(-100vh) translateX(100px) rotate(360deg);
            opacity: 0;
          }
        }
        
        @keyframes fade-in {
          from { opacity: 0; }
          to { opacity: 1; }
        }
        
        .heart-float {
          position: fixed;
          font-size: 2rem;
          animation: float 8s infinite linear;
          pointer-events: none;
          z-index: 0;
          color: rgba(255, 255, 255, 0.6); /* Semi-transparent white hearts */
        }
        
        .animate-fade-in {
          animation: fade-in 0.5s ease-in;
        }
      `}} />

      {/* Floating Hearts Container */}
      <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
        <div className="heart-float" style={{left: '5%', animationDelay: '0s'}}>❤️</div>
        <div className="heart-float" style={{left: '15%', animationDelay: '1s'}}>❤️</div>
        <div className="heart-float" style={{left: '25%', animationDelay: '2s'}}>❤️</div>
        <div className="heart-float" style={{left: '35%', animationDelay: '3s'}}>❤️</div>
        <div className="heart-float" style={{left: '45%', animationDelay: '4s'}}>❤️</div>
        <div className="heart-float" style={{left: '55%', animationDelay: '5s'}}>❤️</div>
        <div className="heart-float" style={{left: '65%', animationDelay: '6s'}}>❤️</div>
        <div className="heart-float" style={{left: '75%', animationDelay: '7s'}}>❤️</div>
        <div className="heart-float" style={{left: '85%', animationDelay: '1.5s'}}>❤️</div>
        <div className="heart-float" style={{left: '95%', animationDelay: '2.5s'}}>❤️</div>
      </div>

      {/* Content Container */}
      <div className="relative z-10 w-full flex flex-col md:flex-row items-center justify-center gap-12 max-w-7xl mx-auto px-6">
        
        {/* Left Side - Text Content */}
        <div className="flex-1 text-center md:text-left text-white max-w-xl">
          <h1 className="text-5xl md:text-6xl mb-4" style={{ fontFamily: 'Georgia, serif' }}>
            HI DARLING
          </h1>
          <p className="font-pacifico text-3xl mb-8" style={{ color: '#f3e5dc' }}>
            I am so glad you stopped by
          </p>
          
          <div className="space-y-4 text-lg leading-relaxed opacity-90">
            <p>
              I'm Giana, an author of Canadian romance. I live on a beautiful island on the west coast... with my husband and my Golden Retriever, Romeo.
            </p>
            <p>
              Here are a few other things:
              1. That you love me. 2. That you keep up with my shit. 3. You are handsome. 4. You are too handsome. 5. The sex is godd. 6. You always feed me. 7. You are kind. 8. You are bholu bandar. 7. You bandar. 9. You have me. 10. You're smart & talented.
            </p>
            <p>
              My love story is my favorite...
            </p>
          </div>
          
          <p className="font-pacifico text-4xl mt-12 mb-8" style={{ color: '#f3e5dc' }}>
            xoxo, Giana
          </p>
          
          <button className="px-6 py-2 border border-white text-white hover:bg-white hover:text-[#c87e7e] transition-colors text-lg uppercase tracking-wider">
            More About Me
          </button>
        </div>

        {/* Right Side - Photo Layout */}
        <div className="flex-1 flex flex-col items-center md:items-end justify-center relative mt-12 md:mt-0">
          {/* Top Polaroid */}
          <div className="bg-white p-3 shadow-xl transform rotate-[-3deg] w-80 md:w-96 mb-[-60px] z-10 border-[12px] border-white">
            <img 
              src="/top_photo.jpg" // Replace with your top image path
              alt="Giana holding book" 
              className="w-full h-auto object-cover aspectRatio-[4/3]"
            />
          </div>
          
          {/* Bottom Polaroid */}
          <div className="bg-white p-3 shadow-2xl transform rotate-[2deg] w-80 md:w-96 z-0 border-[12px] border-white">
            <img 
              src="/bottom_photo.jpg" // Replace with your bottom image path
              alt="Giana smiling with books" 
              className="w-full h-auto object-cover aspectRatio-[4/3]"
            />
          </div>
        </div>
      </div>
    </div>
  );
}
